// // This module increments the counter on each positive clock edge and resets it to 0 when the reset signal is active.
module down_counter (
    input               clk,
    input               rst,
    output reg [3:0]    count
);

    always @(posedge clk) begin
        if (rst) begin
            count <= 4'b1111;
        end else begin
            count <= count - 1;
        end
    end

endmodule
